var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"흑...... 흐윽......","JPN":"う……ううっ……","ENG":"*Sob sob*","TWN":"嗚嗚嗚……嗚嗚嗚……"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"미안해, 에이미...... 정말 미안해......","JPN":"ごめんね。エイミー……本当にごめんね……","ENG":"I'm sorry, Amy... I'm so sorry...","TWN":"對不起，艾米……真的對不起……"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그때 가는 걸 말렸으면 이런 일은 없었을 텐데.......","JPN":"あの時、行くのを止めていたら、こんなことはなかったはずなのに……","ENG":"I should have stopped you while I could...","TWN":"如果當時我們有阻止妳去的話，就不會發生這樣的事情了……"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"하다못해 우리가...... 따라가기라도 했으면...... 어쩌면......","JPN":"せめて私たちが……ついて行ってたら……もしかしたら……","ENG":"If we... If we... Followed you... Then maybe...","TWN":"至少讓我們……跟著一起去的話……應該也不會……"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"......시신도 수습하지 못했다면서요?","JPN":"……遺体の収容もできなかったんだって？","ENG":"I heard you couldn't find the body?","TWN":"……聽說連收屍都沒辦法？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"전투가 벌어지는 동안 휘말렸겠지. 꽤 큰 규모의 재난이었다고 하니까 어쩔 수 없었을 거야.","JPN":"戦闘の最中に流失しただろうね。かなり大規模だったらしいから、どうしようもなかったと思うよ。","ENG":"It probably got lost during the battle. It was a pretty serious disaster, so it's possible.","TWN":"她是被捲入戰鬥中的。而且是規模相當大的一場災難，所以無能為力。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"그나저나 들었어요? 이번 일은 단순한 침식 재난이 아니라고 하는 말도......","JPN":"それはそうと、聞きました？　今回のことは単なる侵食災害ではない噂もあって……","ENG":"Anyway, did you hear? They're saying this wasn't a simple corruption disaster...","TWN":"你聽說了嗎？有人說，這次不是一場單純的侵蝕災難……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......선배?","JPN":"……先輩？","ENG":"...Shiyoon?","TWN":"……前輩？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"여긴 뭐하러 온 거야?","JPN":"何しにここへ？","ENG":"What are you doing here?","TWN":"你來這裡幹什麼？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아, 미나 양. 이거 우연히 마주쳤네요.","JPN":"あ、ミナさん。これは奇遇ですね。","ENG":"Oh, Mina. Fancy seeing you here!","TWN":"啊，米娜小姐，真是巧遇呢。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하. 보시다시피 조문 왔습니다.","JPN":"見てのとおり弔問にきました。","ENG":"Haha. I came to pay my respects.","TWN":"哈哈，如妳所見，我也是來弔唁的。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......우연은 무슨. 미행이라도 한 거겠지.","JPN":"……奇遇も何も。尾行でもしたんじゃないの？","ENG":"Yeah right... You've been following me.","TWN":"……什麼巧遇？你是在跟蹤我吧。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이런, 눈치채셨나요?","JPN":"おや、気づかれてましたか。","ENG":"Oops. I thought I was being pretty sneaky.","TWN":"哎呀，被發現了嗎？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 뭐, 이것도 다 사랑하는 후배님을 걱정하는 마음에서 신경을 쓰는 거랄까요?","JPN":"でもまあ、愛する後輩を心配したあまり、自然と足が向いたといいましょうか。","ENG":"What can I say? I'm just concerned for my rookie teammate whom I care about deeply.","TWN":"但這也是因為擔心我心愛的後輩，所以才這麼費心的啊？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"또 그렇게 능구렁이처럼.......","JPN":"またそんなとぼけたことを言って……","ENG":"Blegh...","TWN":"又來了，像個老油條一樣……"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그리고......","JPN":"それから……","ENG":"Besides...","TWN":"還有……"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"한 가지 마음에 걸리는 점도 있고 해서요.","JPN":"1つ気になることがありましてね。","ENG":"There's something that's been bothering me.","TWN":"有個讓我有點在意的地方。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"마음에 걸리다니......?","JPN":"気になること…？","ENG":"Something's been bothering you?","TWN":"在意……？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"에이미 양은 프리라이더 외엔 장례를 치러 줄 사람이 없는 것 같더군요.","JPN":"エイミーさんはフリーライダー以外、お葬式をしてくれる人がいないようでした。","ENG":"I don't think Amy has anyone who can give her a proper funeral aside from the other Free Riders.","TWN":"因為除了自由騎士以外，似乎沒有能為艾米小姐舉行葬禮的人了。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"가족이나 친지에 대해서 들어본 사람도 없고요.","JPN":"家族や親戚について知っている人もいないようですし。","ENG":"She didn't mention any family or relatives, did she?","TWN":"也沒有聽說過她有家人或親戚之類的。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"평소에 붙임성이 많은 성격이라고 들었는데 어떻게 된 일일까요......?","JPN":"普段、親しみやすい性格だったと聞きましたが、どうしてでしょうね。","ENG":"I heard she was very friendly, so it's a bit odd... Don't you think?","TWN":"但聽說她平時的性格很活潑啊，那這是怎麼回事呢？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......그게 어디가 이상하단 거야?","JPN":"……それのどこがおかしいと言うの？","ENG":"What's odd about it?","TWN":"……哪裡奇怪了？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"요즘 시대에 그런 경우가 드문 것도 아니잖아. 나만 해도......","JPN":"今時そんな人、珍しいわけでもないじゃない。私だって……","ENG":"It's not uncommon for people to lose contact with their family these days. Myself included...","TWN":"在這個時代，這種情況又不是很罕見，像我也是這樣……"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하. 그러게 말입니다.","JPN":"はは、そうですよね。","ENG":"Haha. I guess that's true.","TWN":"哈哈，說得也是。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이게 다 도시화와 핵가족의 비극이죠.","JPN":"これらすべては、都市化と核家族化が生み出した悲劇です。","ENG":"This is the tragedy of the nuclear family in the midst of urbanization.","TWN":"這就是都市化和核心家庭的悲劇呢。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"우린 그런 일이 생기지 않도록, 언제 한 번 소대의 전우애를 돈독히 할 수 있는 자리를 마련해 봐야겠네요.","JPN":"僕たちにはそんなことがないように、いつか隊員同志の親睦を深める場を設けてみましょう。","ENG":"We should find an opportunity to bond as teammates so that this doesn't happen to us!","TWN":"為了避免這種事，我們哪天也該辦個加深小隊戰友感情的活動才對。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그럼 미나 양, 조문하고 오세요.","JPN":"では、ミナさん、行ってらっしゃい。","ENG":"Anyway. Go on and pay your respects, Mina.","TWN":"那麼米娜小姐，妳就去參加弔唁吧。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"기다리고 있겠습니다.","JPN":"待っていますね。","ENG":"I'll wait for you here.","TWN":"我會等妳的。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"응. 대장. 끝냈어.","JPN":"うん、隊長。終わったよ。","ENG":"Yes, Commander. It's done.","TWN":"嗯，隊長。都結束了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"억제기에 들어있던 인자 추출기 코어도 챙겼고 뒤처리도 깔끔하게 마무리했지.","JPN":"抑制装置に入っていた因子抽出器のコアも取りそろえたし、後始末も完璧だよ。","ENG":"I got the Factor Extractor Core from the Inhibitor and cleaned everything up nicely too.","TWN":"不但拿到了抑制器中的因子萃取器核心，善後也處理得很乾淨。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"택배로 보내놨으니까 내일쯤 도착할 거야. 하하.","JPN":"宅急便で送ったから、明日には着くと思うよ、はは。","ENG":"I mailed you the package, so you'll probably get it tomorrow. Haha.","TWN":"我是用快遞寄出去的，所以大概明天就會送到吧，哈哈。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"아, 별로 어려운 건 없었는데...... 약한 척하기 엄청 힘들더라고.","JPN":"あ、とくに難しいことはなかったけど、弱いふりをするのが大変だったよ。","ENG":"There was nothing complicated about it... The hardest thing was pretending to be weak.","TWN":"啊，這沒什麼難的……就只是裝弱有點難而已。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"리플레이서 나이트인가 뭔가 하는 얼간이가 하도 멍청하게 굴어서 말이야.","JPN":"リプレイサー・ナイトとやらがあまりにもバカなやつでね。","ENG":"That dimwit calling herself the Replacer Knight was such an idiot.","TWN":"克隆·騎士根本是個胡搞瞎搞，不知道自己做什麼的呆子。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"실수로 죽여버릴까 봐 엄청 고생했다니까.","JPN":"間違って殺しちゃいそうで、ものすごくヒヤヒヤしたんだよ。","ENG":"I had to be careful not to kill her by accident.","TWN":"要裝作不小心被她殺死，我還真花了不少功夫呢。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"......그나저나 이번엔 꽤 마음에 드는 신분이었는데, 이렇게 끝내려니까 아쉽네.","JPN":"……それにしても、今回の役はかなり気に入ってたから、これで終わりだと思うとさみしいな。","ENG":"Anyway... I really enjoyed playing this role for once. Too bad I had to leave it behind like that.","TWN":"……不過，我蠻喜歡這次的身份呢，就這樣結束還真有點可惜。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"뭐...... 그래도 자기 장례식에 참석하는 경험은 꽤 재미있는걸?","JPN":"まあ……でも、自分のお葬式に出るというのはなかなか面白いね。","ENG":"But... It's actually kind of fun attending my own funeral.","TWN":"還有……參加自己葬禮的經驗，真的很有趣呢。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"조화도 하나 놓고 왔지롱. 헤헤.","JPN":"造花も一輪置いてきたよ。へへっ。","ENG":"I even left myself some flowers. Heh.","TWN":"還有人為我放了個花圈呢，嘿嘿。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"응? 아, 걔?","JPN":"うん？　あ～、あの子？","ENG":"Huh? Oh, her?","TWN":"嗯？啊，她呀？"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"으으음...... 아직은 한참 모자라던데?","JPN":"ううん……まだまだ全然足りないよ？","ENG":"Hmm... I think she still has a long way to go...","TWN":"嗯……暫時還不太行吧？"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"저래 가지고 정말 우리 계획에 도움이 되는 거 맞아?","JPN":"あれで本当に私たちの計画に役立つの？","ENG":"Are you sure she's going to be of any help to our plan like that?","TWN":"這樣真的會對我們的計畫有幫助嗎？"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"아하하! 알았어. 대장. 대장이 다 생각이 있겠지.","JPN":"あはは！　わかったよ、隊長。隊長のことだし、思うところがあると思うから。","ENG":"Hahaha! Okay. Fine, Commander. I'm sure you know what you're doing.","TWN":"啊哈哈哈！我知道了，隊長。隊長也有自己的想法對吧。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"......그럼 기대하고 있을게.","JPN":"……それじゃ楽しみにしてるよ。","ENG":"I'm looking forward to it...","TWN":"……那我就拭目以待了。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"                                                                                                 Episode. 2 Fin.","JPN":"Episode. 2 Fin.","ENG":"                                                                                                 Episode 2 Complete.","TWN":"                                                                                                 Episode. 2 Fin."},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"}]`);export{e as default};